class Solution {
public:
    int distinctSequences(int n) {
        if (n == 1) return 6;
        const int MOD = 1'000'000'007;
        int dp[10001][7][7] = {};
        for (int a = 1; a <= 6; ++a)
            for (int b = 1; b <= 6; ++b)
                if (a != b && std::gcd(a, b) == 1)
                    dp[2][a][b] = 1;

        for (int len = 3; len <= n; ++len) {
            int ndp[7][7] = {};
            for (int a = 1; a <= 6; ++a) {
                for (int b = 1; b <= 6; ++b) {
                    if (a == b || std::gcd(a, b) != 1) continue;
                    for (int c = 1; c <= 6; ++c) {
                        if (c == a || c == b || std::gcd(b, c) != 1) continue;
                        ndp[b][c] = (ndp[b][c] + dp[len - 1][a][b]) % MOD;
                    }
                }
            }
            for (int a = 1; a <= 6; ++a)
                for (int b = 1; b <= 6; ++b)
                    dp[len][a][b] = ndp[a][b];
        }

        long long ans = 0;
        for (int a = 1; a <= 6; ++a)
            for (int b = 1; b <= 6; ++b)
                ans = (ans + dp[n][a][b]) % MOD;
        return static_cast<int>(ans);
    }
};
